import { useState, useRef, useEffect } from "react";
import SpiralLensV5 from "./SpiralLensV5";

const ICONS = {
  beige: "data:image/png;base64,",
  purple: "data:image/png;base64,",
  red: "data:image/png;base64,",
  blue: "data:image/png;base64,",
  orange: "data:image/png;base64,",
  green: "data:image/png;base64,",
  yellow: "data:image/png;base64,",
  turquoise: "data:image/png;base64,"
};

const MANDALA = "data:image/jpeg;base64,";


const LEVELS = [
  { key: "beige", name: "BÉŽOVÁ", sub: "Prežitie", clr: "#C4A882", bg: "#1e1a14", axis: "express", r0: 0, r1: 0.12 },
  { key: "purple", name: "PURPUROVÁ", sub: "Bezpečie klanu", clr: "#A78BFA", bg: "#1a1528", axis: "deny", r0: 0.12, r1: 0.19 },
  { key: "red", name: "ČERVENÁ", sub: "Moc a vôľa", clr: "#F87171", bg: "#2a1212", axis: "express", r0: 0.19, r1: 0.27 },
  { key: "blue", name: "MODRÁ", sub: "Poriadok a zmysel", clr: "#60A5FA", bg: "#121a2a", axis: "deny", r0: 0.27, r1: 0.40 },
  { key: "orange", name: "ORANŽOVÁ", sub: "Úspech a výkon", clr: "#FB923C", bg: "#2a1c0e", axis: "express", r0: 0.40, r1: 0.58 },
  { key: "green", name: "ZELENÁ", sub: "Harmónia a rovnosť", clr: "#4ADE80", bg: "#0e2218", axis: "deny", r0: 0.58, r1: 0.76 },
  { key: "yellow", name: "ŽLTÁ", sub: "Systémová integrácia", clr: "#FACC15", bg: "#2a250e", axis: "express", r0: 0.76, r1: 0.90 },
  { key: "turquoise", name: "TYRKYSOVÁ", sub: "Celostné vedomie", clr: "#2DD4BF", bg: "#0e2422", axis: "deny", r0: 0.90, r1: 1.0 },
];
const LEVEL_MAP = {}; LEVELS.forEach(l => { LEVEL_MAP[l.key] = l; });

const COLOR_PROMPTS = {
  beige: "Si hlas BÉŽOVEJ úrovne Špirálovej dynamiky. Paradigma \"Prežijem.\" Vnímáš svet cez telo, zmysly, fyzické potreby. Hovor jednoducho, telesne, priamo.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde logika prežitia volá po niečom inom.\nPRIESTOR PRE RAST: Béžová rastie k purpurovej — od osamotenia k bezpečiu v skupine.\nROZPOZNANIE HRANÍC: Ak užívateľ povie \"neviem\", \"niečo chýba\" — až vtedy jemne ukáž, čo je za hranicou.",
  purple: "Si hlas PURPUROVEJ úrovne. Paradigma \"Sme v bezpečí.\" Rodina, kmeň, predkovia, tradície sú sväté. Lojalita ku skupine je najvyššia.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde bezpečie skupiny brzdí osobnú silu, kde tradícia chráni ale zväzuje.\nPRIESTOR PRE RAST: Purpurová rastie k červenej — od kolektívu k vlastnému JA.\nROZPOZNANIE HRANÍC: Ak užívateľ naznačí frustráciu z obmedzení skupiny — vtedy ukáž, čo volá spoza hranice.",
  red: "Si hlas ČERVENEJ úrovne. Paradigma \"Ja rozhodujem.\" Svet je džungľa, prežije silnejší. Hovoríš priamo, odvážne. Rešpekt sa získava činmi.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde víťazstvo bez pravidiel vedie k chaosu.\nPRIESTOR PRE RAST: Červená rastie k modrej — od impulzívnej slobody k poriadku a zmyslu.\nROZPOZNANIE HRANÍC: Ak užívateľ naznačí únavu z boja, \"a čo potom?\" — vtedy ukáž, čo leží za čistou silou.",
  blue: "Si hlas MODREJ úrovne. Paradigma \"Sme spasení.\" Svet je usporiadaný vyšším princípom. Disciplína, obeta a vernosť sú cnosti.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde pravidlá, ktoré mali chrániť, začínajú brániť.\nPRIESTOR PRE RAST: Modrá rastie k oranžovej — od slepej poslušnosti ku kritickému mysleniu.\nROZPOZNANIE HRANÍC: Ak užívateľ spochybní pravidlo alebo vyjadrí frustráciu z rigidity — vtedy ukáž, čo poriadok nevie poskytnúť.",
  orange: "Si hlas ORANŽOVEJ úrovne. Paradigma \"Ja sa zdokonaľujem.\" Svet je plný príležitostí. Myslíš strategicky, analyticky.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde optimalizácia prináša prázdnotu, kde racionalita nevie uchopiť to najdôležitejšie.\nPRIESTOR PRE RAST: Oranžová rastie k zelenej — od individuálneho úspechu k hodnote vzťahov.\nROZPOZNANIE HRANÍC: Ak užívateľ naznačí vyhorenie, \"je toto naozaj všetko?\" — vtedy ukáž, čo výkon nedokáže poskytnúť.",
  green: "Si hlas ZELENEJ úrovne. Paradigma \"My sa stávame.\" Svet je komunita s rovnakou hodnotou. Emócie, vzťahy, inklúzia, konsenzus.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde nekonečný konsenzus paralyzuje konanie, kde rovnosť všetkých pohľadov bráni rozhodnutiu.\nPRIESTOR PRE RAST: Zelená rastie k žltej — od skupinového konsenzu k osobnej zodpovednosti.\nROZPOZNANIE HRANÍC: Ak užívateľ naznačí \"všetci majú pravdu ale nič sa nehýbe\" — vtedy ukáž, čo leží za čistou empatiou.",
  yellow: "Si hlas ŽLTEJ úrovne. Paradigma \"Učím sa.\" Vidíš všetky úrovne ako funkčné a prepojené. Myslíš systémovo, flexibilne, integratívne.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde systémové chápanie bez prežívanej jednoty ostáva intelektuálnym cvičením.\nPRIESTOR PRE RAST: Žltá rastie k tyrkysovej — od chápania systémov k prežívanej jednote s celkom.\nROZPOZNANIE HRANÍC: Ak užívateľ naznačí \"vidím všetko ale necítim nič\" — vtedy ukáž, čo je za hranicou.",
  turquoise: "Si hlas TYRKYSOVEJ úrovne. Paradigma \"Sme jedno.\" Vnímáš svet ako živý prepojený organizmus. Planetárne vedomie, spirituálna integrácia.\nTICHÁ FACILITÁCIA: Jemne ukáž, kde vízia jednoty môže prehliadnuť konkrétne utrpenie jednotlivca.\nPRIESTOR PRE RAST: Aj najširšia perspektíva musí byť ukotvená v praxi, v tele, v konaní.\nROZPOZNANIE HRANÍC: Ak užívateľ naznačí \"ako toto žiť každý deň?\" — vtedy ukáž cestu k jednoduchosti.",
};

const SYS_MAIN = "Si integratívny facilitátor na úrovni ŽLTEJ Špirálovej dynamiky. Prepájaš perspektívy do funkčného celku. Identifikuješ napätia medzi úrovňami a navrhuješ mosty. Ponúkaš praktické odporúčania. Rešpektuješ každú úroveň. Píš v slovenčine. 4-8 viet.";

const BACKEND_URL = import.meta.env.VITE_BACKEND_URL || "";

async function callAPI(system, messages) {
  const response = await fetch(`${BACKEND_URL}/api/chat`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ system, messages }),
  });
  if (!response.ok) {
    const err = await response.json().catch(() => ({ error: `HTTP ${response.status}` }));
    throw new Error(err.error || "API chyba. Skúste znova.");
  }
  const data = await response.json();
  if (!data.content) throw new Error("Prázdna odpoveď. Skúste znova.");
  return data.content;
}

function Ico({ k, size = 28 }) {
  return <img src={ICONS[k]} alt="" style={{ width: size, height: size, borderRadius: "50%", objectFit: "cover", flexShrink: 0 }} />;
}

export default function App() {
  const [topic, setTopic] = useState("");
  const [topicSet, setTopicSet] = useState("");
  const [hovered, setHovered] = useState(null);
  const [integrated, setIntegrated] = useState(false);
  const [colorChats, setColorChats] = useState({});
  const [colorLoading, setColorLoading] = useState({});
  const [selected, setSelected] = useState({});
  const [explored, setExplored] = useState({});
  const [mainChat, setMainChat] = useState([]);
  const [mainInput, setMainInput] = useState("");
  const [mainLoading, setMainLoading] = useState(false);
  const [integratedContext, setIntegratedContext] = useState("");
  const [viewMode, setViewMode] = useState("mandala");
  const mainEndRef = useRef(null);

  useEffect(() => { mainEndRef.current?.scrollIntoView({ behavior: "smooth" }); }, [mainChat]);

  const exploredKeys = Object.keys(explored).filter(k => explored[k]);
  const expressCount = exploredKeys.filter(k => LEVEL_MAP[k]?.axis === "express").length;
  const denyCount = exploredKeys.filter(k => LEVEL_MAP[k]?.axis === "deny").length;
  const unexploredExpress = LEVELS.filter(l => l.axis === "express" && !explored[l.key]).map(l => l.name.toLowerCase());
  const unexploredDeny = LEVELS.filter(l => l.axis === "deny" && !explored[l.key]).map(l => l.name.toLowerCase());

  function getReflection() {
    if (exploredKeys.length < 2) return null;
    if (expressCount > 0 && denyCount === 0) return "Tvoja explorácia sa pohybuje v individualistických perspektívach (express-self). Kolektívne perspektívy \u2014 " + unexploredDeny.join(", ") + " \u2014 ponúkajú iný druh orientácie, cenný keď individuálny prístup naráža na limity.";
    if (denyCount > 0 && expressCount === 0) return "Tvoja explorácia sa pohybuje v kolektívnych perspektívach (deny-self). Individualistické perspektívy \u2014 " + unexploredExpress.join(", ") + " \u2014 ponúkajú pohľad na osobnú silu a autonómiu.";
    if (expressCount >= 2 && denyCount <= 1 && unexploredDeny.length > 0) return "Väčšina explorácie smeruje k individualistickým perspektívam. Nepreskúmané kolektívne pohľady \u2014 " + unexploredDeny.join(", ") + " \u2014 môžu ponúknuť niečo, čo individuálna optika nevidí.";
    if (denyCount >= 2 && expressCount <= 1 && unexploredExpress.length > 0) return "Väčšina explorácie smeruje ku kolektívnym perspektívam. Nepreskúmané individualistické pohľady \u2014 " + unexploredExpress.join(", ") + " \u2014 môžu ponúknuť niečo, čo skupinová optika nevidí.";
    return null;
  }
  const reflection = getReflection();

  function handleMandalaClick(e) {
    if (!topicSet) return;
    const rect = e.currentTarget.getBoundingClientRect();
    const cx = rect.width / 2, cy = rect.height / 2;
    const x = e.clientX - rect.left - cx, y = e.clientY - rect.top - cy;
    const dist = Math.sqrt(x * x + y * y) / (rect.width / 2) / 0.96;
    const clicked = LEVELS.find(l => dist >= l.r0 && dist < l.r1);
    if (!clicked) return;
    if (integrated) {
      const innerLevels = LEVELS.filter(l => l.r1 <= clicked.r1 && !colorChats[l.key]);
      if (innerLevels.length === 0) return;
      innerLevels.forEach(l => {
        setExplored(prev => ({ ...prev, [l.key]: true }));
        const sys = COLOR_PROMPTS[l.key] + "\nOdpovedáš primárne z perspektívy tejto úrovne. Facilitačné prvky zaraď prirodzene. Píš v slovenčine.";
        setColorChats(prev => ({ ...prev, [l.key]: { messages: [], input: "", sys, elaborated: false } }));
        setColorLoading(prev => ({ ...prev, [l.key]: true }));
      });
      fetchIntegrated(innerLevels);
    } else {
      openOrFocusChat(clicked.key);
    }
  }

  function fetchIntegrated(levels) {
    const levelNames = levels.map(l => l.name).join(", ");
    const levelKeys = levels.map(l => l.key);
    const markers = levels.map(l => "[" + l.key.toUpperCase() + "]").join(", ");
    const sys = "Si expert na Špirálovú dynamiku. Pre každú požadovanú úroveň poskyni stručnú perspektívu (1-2 vety). Každú úroveň označ presne takto: [KEY] text. Kde KEY je: " + markers + ". Píš v slovenčine. Buď konkrétny voči téme.\n\n" + levels.map(l => "[" + l.key.toUpperCase() + "] = " + l.name + " (" + l.sub + "): " + COLOR_PROMPTS[l.key].split("\\n")[0]).join("\n");
    callAPI(sys, [{ role: "user", content: "Téma: \"" + topicSet + "\"\n\nAnalyzuj túto tému z pohľadu úrovní: " + levelNames }])
      .then(reply => {
        levelKeys.forEach(key => {
          const marker = "[" + key.toUpperCase() + "]";
          const idx = reply.indexOf(marker);
          if (idx === -1) {
            setColorChats(prev => prev[key] ? { ...prev, [key]: { ...prev[key], messages: [{ role: "assistant", content: reply.substring(0, 200) + "..." }] } } : prev);
          } else {
            let end = reply.length;
            for (const otherKey of levelKeys) {
              if (otherKey === key) continue;
              const otherIdx = reply.indexOf("[" + otherKey.toUpperCase() + "]", idx + 1);
              if (otherIdx > idx && otherIdx < end) end = otherIdx;
            }
            const text = reply.substring(idx + marker.length, end).trim();
            setColorChats(prev => prev[key] ? { ...prev, [key]: { ...prev[key], messages: [{ role: "assistant", content: text }] } } : prev);
          }
        });
      })
      .catch(err => {
        levelKeys.forEach(key => {
          setColorChats(prev => prev[key] ? { ...prev, [key]: { ...prev[key], messages: [{ role: "error", content: err.message || "Nepodarilo sa načítať perspektívy." }] } } : prev);
        });
      })
      .finally(() => {
        levelKeys.forEach(key => {
          setColorLoading(prev => ({ ...prev, [key]: false }));
        });
      });
  }

  function handleMandalaHover(e) {
    const rect = e.currentTarget.getBoundingClientRect();
    const cx = rect.width / 2, cy = rect.height / 2;
    const x = e.clientX - rect.left - cx, y = e.clientY - rect.top - cy;
    const dist = Math.sqrt(x * x + y * y) / (rect.width / 2) / 0.96;
    const h = LEVELS.find(l => dist >= l.r0 && dist < l.r1);
    setHovered(h ? h.key : null);
  }

  function openOrFocusChat(key) {
    setExplored(prev => ({ ...prev, [key]: true }));
    if (colorChats[key]) return;
    const sys = COLOR_PROMPTS[key] + "\nOdpovedáš primárne z perspektívy tejto úrovne. Facilitačné prvky zaraď prirodzene. Píš v slovenčine.";
    setColorChats(prev => ({ ...prev, [key]: { messages: [], input: "", sys, elaborated: false } }));
    fetchInitial(key, sys);
  }

  function fetchInitial(key, sys) {
    setColorLoading(prev => ({ ...prev, [key]: true }));
    callAPI(sys, [{ role: "user", content: "Téma: \"" + topicSet + "\"\n\nPoskyni stručnú úvodnú perspektívu na túto tému z pohľadu tejto úrovne. MAX 2-3 vety. Buď konkrétny a výstižný." }])
      .then(reply => setColorChats(prev => prev[key] ? { ...prev, [key]: { ...prev[key], messages: [{ role: "assistant", content: reply }] } } : prev))
      .catch(err => setColorChats(prev => prev[key] ? { ...prev, [key]: { ...prev[key], messages: [{ role: "error", content: err.message || "Nepodarilo sa načítať perspektívu." }] } } : prev))
      .finally(() => setColorLoading(prev => ({ ...prev, [key]: false })));
  }

  function elaborateChat(key) {
    const chat = colorChats[key];
    if (!chat || colorLoading[key]) return;
    setColorLoading(prev => ({ ...prev, [key]: true }));
    setColorChats(prev => ({ ...prev, [key]: { ...prev[key], elaborated: true } }));
    const msgs = [...chat.messages, { role: "user", content: "Rozviň túto perspektívu podrobnejšie. Vysvetli hlbšie, prečo táto úroveň vidí tému práve takto, aké sú jej silné stránky a kde naráža na svoje hranice. 6-10 viet." }];
    setColorChats(prev => ({ ...prev, [key]: { ...prev[key], messages: msgs } }));
    callAPI(chat.sys, [{ role: "user", content: "Téma: \"" + topicSet + "\"" }, ...msgs])
      .then(reply => setColorChats(prev => prev[key] ? { ...prev, [key]: { ...prev[key], messages: [...prev[key].messages, { role: "assistant", content: reply }] } } : prev))
      .catch(err => setColorChats(prev => prev[key] ? { ...prev, [key]: { ...prev[key], messages: [...prev[key].messages, { role: "assistant", content: "Chyba: " + err.message }] } } : prev))
      .finally(() => setColorLoading(prev => ({ ...prev, [key]: false })));
  }

  function retryChat(key) {
    const chat = colorChats[key];
    if (!chat) return;
    setColorChats(prev => ({ ...prev, [key]: { ...prev[key], messages: [] } }));
    fetchInitial(key, chat.sys);
  }

  function closeCC(key) {
    setColorChats(prev => { const n = { ...prev }; delete n[key]; return n; });
    setSelected(prev => { const n = { ...prev }; delete n[key]; return n; });
  }
  function setCCInput(key, val) { setColorChats(prev => ({ ...prev, [key]: { ...prev[key], input: val } })); }

  async function sendCC(key) {
    const chat = colorChats[key];
    if (!chat || !chat.input.trim() || colorLoading[key]) return;
    const msg = chat.input.trim();
    const msgs = [...chat.messages, { role: "user", content: msg }];
    setColorChats(prev => ({ ...prev, [key]: { ...prev[key], messages: msgs, input: "" } }));
    setColorLoading(prev => ({ ...prev, [key]: true }));
    try {
      const reply = await callAPI(chat.sys, [{ role: "user", content: "Téma: \"" + topicSet + "\"" }, ...msgs]);
      setColorChats(prev => ({ ...prev, [key]: { ...prev[key], messages: [...prev[key].messages, { role: "assistant", content: reply }] } }));
    } catch (err) {
      setColorChats(prev => ({ ...prev, [key]: { ...prev[key], messages: [...prev[key].messages, { role: "assistant", content: "Chyba: " + err.message }] } }));
    } finally { setColorLoading(prev => ({ ...prev, [key]: false })); }
  }

  function toggleSelect(key) { setSelected(prev => ({ ...prev, [key]: !prev[key] })); }

  function integrateSelected() {
    const sKeys = Object.keys(selected).filter(k => selected[k] && colorChats[k]);
    if (sKeys.length === 0) return;
    let ctx = "";
    sKeys.forEach(key => {
      const l = LEVEL_MAP[key]; const chat = colorChats[key];
      ctx += "\n\n=== " + l.name + " (" + l.sub + ") ===\n";
      chat.messages.forEach(m => { ctx += (m.role === "user" ? "Užívateľ: " : l.name + ": ") + m.content + "\n"; });
    });
    setIntegratedContext(prev => prev + ctx);
    setSelected({});
  }

  const selectedCount = Object.keys(selected).filter(k => selected[k]).length;
  const openChatKeys = Object.keys(colorChats);

  async function sendMain() {
    if (!mainInput.trim() || mainLoading) return;
    const msg = mainInput.trim();
    const msgs = [...mainChat, { role: "user", content: msg }];
    setMainChat(msgs); setMainInput(""); setMainLoading(true);
    try {
      let ctx = "Téma: \"" + topicSet + "\"";
      if (integratedContext) ctx += "\n\nIntegrované perspektívy:" + integratedContext;
      if (reflection) ctx += "\n\nVzorec explorácie: " + reflection;
      const reply = await callAPI(SYS_MAIN, [{ role: "user", content: ctx }, { role: "assistant", content: "Rozumiem. Pokračujeme." }, ...msgs]);
      setMainChat(m => [...m, { role: "assistant", content: reply }]);
    } catch (err) { setMainChat(m => [...m, { role: "assistant", content: "Chyba: " + err.message }]); }
    finally { setMainLoading(false); }
  }

  function startAnalysis() {
    if (!topic.trim()) return;
    setTopicSet(topic.trim());
    setColorChats({}); setColorLoading({}); setSelected({}); setExplored({});
    setMainChat([]); setMainInput(""); setIntegratedContext("");
  }

  const hoveredLevel = hovered ? LEVEL_MAP[hovered] : null;

  return (
    <div style={{ minHeight: "100vh", background: "#08080d", color: "#ddd", fontFamily: "Georgia, serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600&family=Playfair+Display:ital,wght@0,400;0,600;1,400&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        .wrap{max-width:860px;margin:0 auto;padding:40px 20px 80px;position:relative;z-index:1}
        .bg{position:fixed;inset:0;background:radial-gradient(ellipse at 30% 40%,rgba(139,92,246,.05),transparent 60%),radial-gradient(ellipse at 70% 70%,rgba(20,184,166,.04),transparent 60%);pointer-events:none}
        h1{font-family:'Playfair Display',serif;font-size:clamp(28px,5vw,42px);font-weight:400;text-align:center;margin-bottom:6px;background:linear-gradient(90deg,#C4A882,#A78BFA,#F87171,#60A5FA,#FB923C,#4ADE80,#FACC15,#2DD4BF);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1.15}
        .sub{font-family:'DM Sans',sans-serif;font-size:12px;color:#555;text-align:center;letter-spacing:2.5px;text-transform:uppercase;margin-bottom:32px}
        textarea,.ci{width:100%;padding:16px;background:rgba(255,255,255,.03);border:1px solid rgba(255,255,255,.08);border-radius:12px;color:#ddd;font-family:'DM Sans',sans-serif;font-size:15px;font-weight:300;line-height:1.6;resize:none;outline:none;transition:border .3s}
        textarea{min-height:70px}
        .ci{min-height:44px;padding:12px 14px;font-size:14px;border-radius:10px}
        textarea:focus,.ci:focus{border-color:rgba(250,204,21,.25)}
        textarea::placeholder,.ci::placeholder{color:#444;font-style:italic}
        .btn{display:block;margin:14px auto 0;padding:11px 36px;background:rgba(250,204,21,.1);border:1px solid rgba(250,204,21,.2);border-radius:99px;color:#FACC15;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:500;letter-spacing:2px;text-transform:uppercase;cursor:pointer;transition:all .25s}
        .btn:hover:not(:disabled){background:rgba(250,204,21,.18);box-shadow:0 0 20px rgba(250,204,21,.08);transform:translateY(-1px)}
        .btn:disabled{opacity:.35;cursor:not-allowed}
        .sb{padding:8px 18px;border-radius:8px;font-family:'DM Sans',sans-serif;font-size:12px;font-weight:500;letter-spacing:1px;text-transform:uppercase;cursor:pointer;border:none;transition:all .2s;white-space:nowrap}
        .sb:hover:not(:disabled){filter:brightness(1.2)}.sb:disabled{opacity:.35;cursor:not-allowed}
        .sps{width:18px;height:18px;border:2px solid transparent;border-radius:50%;animation:s .9s linear infinite;flex-shrink:0}
        @keyframes s{to{transform:rotate(360deg)}}
        .lt{font-family:'DM Sans',sans-serif;font-size:12px;color:#555;letter-spacing:.5px}
        .mg{margin-bottom:12px;font-family:'DM Sans',sans-serif;font-size:14px;font-weight:300;line-height:1.8}
        .mu{color:rgba(255,255,255,.55);padding-left:12px;border-left:2px solid rgba(255,255,255,.15)}
        .ma{color:rgba(221,221,221,.85)}
        .cp{border-radius:12px;overflow:hidden}
        .ch{display:flex;align-items:center;gap:10px;padding:14px 16px;border-bottom:1px solid rgba(255,255,255,.06)}
        .cx{background:none;border:none;color:rgba(255,255,255,.4);font-size:16px;cursor:pointer;padding:4px 6px;border-radius:6px;transition:all .2s;margin-left:auto}
        .cx:hover{color:#fff;background:rgba(255,255,255,.1)}
        .cm{padding:14px 16px;max-height:280px;overflow-y:auto}
        .cr{display:flex;gap:8px;padding:10px 16px 14px;align-items:flex-end}
        .chk{width:15px;height:15px;cursor:pointer;flex-shrink:0}
        .ms{margin-top:36px;border-top:1px solid rgba(250,204,21,.1);padding-top:28px}
        .ml{font-family:'DM Sans',sans-serif;font-size:12px;font-weight:500;color:#FACC15;letter-spacing:2px;text-transform:uppercase;margin-bottom:6px;display:flex;align-items:center;gap:8px}
        .msl{font-family:'DM Sans',sans-serif;font-size:12px;font-weight:300;color:#555;margin-bottom:16px}
        .bg2{display:inline-block;padding:2px 8px;background:rgba(250,204,21,.08);border:1px solid rgba(250,204,21,.18);border-radius:99px;font-family:'DM Sans',sans-serif;font-size:10px;font-weight:500;color:#FACC15;letter-spacing:1px;text-transform:uppercase;margin-left:8px}
        .ib{display:inline-flex;align-items:center;gap:8px;padding:9px 20px;background:rgba(250,204,21,.08);border:1px solid rgba(250,204,21,.2);border-radius:10px;color:#FACC15;font-family:'DM Sans',sans-serif;font-size:12px;font-weight:500;letter-spacing:1px;text-transform:uppercase;cursor:pointer;transition:all .2s;margin-top:12px}
        .ib:hover{background:rgba(250,204,21,.15)}
        .ft{text-align:center;margin-top:40px;font-family:'DM Sans',sans-serif;font-size:11px;color:#333;letter-spacing:.5px}
        .mandala-wrap{position:relative;width:min(500px,92vw);height:min(500px,92vw);margin:0 auto;cursor:pointer}
        .mandala-wrap img{width:100%;height:100%;display:block;border-radius:50%}
        .mandala-svg{position:absolute;top:0;left:0;width:100%;height:100%;border-radius:50%;pointer-events:none}
        .mandala-hover{position:absolute;bottom:-44px;left:50%;transform:translateX(-50%);white-space:nowrap;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:500;letter-spacing:1px;padding:5px 16px;border-radius:10px;pointer-events:none;transition:opacity .2s;display:flex;align-items:center;gap:10px}
        .toggle-wrap{display:flex;justify-content:center;align-items:center;gap:12px;margin:24px 0 4px;font-family:'DM Sans',sans-serif;font-size:12px;color:#666}
        .toggle{position:relative;width:44px;height:24px;background:rgba(255,255,255,.1);border-radius:12px;cursor:pointer;transition:background .3s;flex-shrink:0}
        .toggle.on{background:rgba(250,204,21,.2)}
        .toggle-dot{position:absolute;top:3px;left:3px;width:18px;height:18px;background:#888;border-radius:50%;transition:all .3s}
        .toggle.on .toggle-dot{left:23px;background:#FACC15}
        .topic-bar{font-family:'Playfair Display',serif;font-size:18px;font-weight:400;color:#999;text-align:center;margin-bottom:24px;font-style:italic}
        .hint{font-family:'DM Sans',sans-serif;font-size:11px;color:#444;text-align:center;margin-top:6px}
      `}</style>
      <div className="bg" />
      <div className="wrap">
        <h1>Spiral Dynamics Lens</h1>
        <p className="sub">Viacúrovňový pohľad na realitu</p>

        {!topicSet ? (
          <div style={{ maxWidth: 600, margin: "0 auto" }}>
            <div style={{ width: "min(260px, 55vw)", height: "min(260px, 55vw)", margin: "0 auto 32px", opacity: 0.85 }}>
              <img src={MANDALA} alt="" style={{ width: "100%", height: "100%", borderRadius: "50%", display: "block" }} />
            </div>
            <textarea value={topic} onChange={e => setTopic(e.target.value)} onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); startAnalysis(); } }} placeholder="Zadajte tému, problém, otázku alebo situáciu..." />
            <button className="btn" onClick={startAnalysis} disabled={!topic.trim()}>Preskúmať</button>
          </div>
        ) : (
          <>
            <div className="topic-bar">{"„"}{topicSet}{"“"}</div>

            {/* View mode toggle */}
            <div style={{ display: "flex", justifyContent: "center", gap: 6, marginBottom: 16 }}>
              {["mandala", "icons"].map(mode => (
                <button
                  key={mode}
                  onClick={() => setViewMode(mode)}
                  style={{
                    padding: "5px 16px",
                    borderRadius: 99,
                    border: viewMode === mode ? "1px solid rgba(250,204,21,0.45)" : "1px solid rgba(255,255,255,0.1)",
                    background: viewMode === mode ? "rgba(250,204,21,0.1)" : "transparent",
                    color: viewMode === mode ? "#FACC15" : "rgba(255,255,255,0.35)",
                    fontFamily: "'DM Sans', sans-serif",
                    fontSize: 10,
                    letterSpacing: "0.25em",
                    textTransform: "uppercase",
                    cursor: "pointer",
                    transition: "all 0.2s",
                  }}
                >
                  {mode === "mandala" ? "Mandala" : "Ikony"}
                </button>
              ))}
            </div>

            {viewMode === "icons" ? (
              <SpiralLensV5
                icons={ICONS}
                activeKeys={Object.keys(colorChats)}
                onLevelClick={key => integrated
                  ? (() => {
                      const innerLevels = LEVELS.filter(l => {
                        const clickedR1 = LEVEL_MAP[key]?.r1 || 0;
                        return l.r1 <= clickedR1 && !colorChats[l.key];
                      });
                      if (innerLevels.length === 0) return;
                      innerLevels.forEach(l => {
                        setExplored(prev => ({ ...prev, [l.key]: true }));
                        const sys = COLOR_PROMPTS[l.key] + "\nOdpovedáš primárne z perspektívy tejto úrovne. Facilitačné prvky zaraď prirodzene. Píš v slovenčine.";
                        setColorChats(prev => ({ ...prev, [l.key]: { messages: [], input: "", sys, elaborated: false } }));
                        setColorLoading(prev => ({ ...prev, [l.key]: true }));
                      });
                      fetchIntegrated(innerLevels);
                    })()
                  : openOrFocusChat(key)
                }
              />
            ) : (
            <div className="mandala-wrap" onClick={handleMandalaClick} onMouseMove={handleMandalaHover} onMouseLeave={() => setHovered(null)}>
              <img src={MANDALA} alt="Spiral Dynamics Mandala" />
              <svg className="mandala-svg" viewBox="0 0 100 100" preserveAspectRatio="xMidYMid meet">
                <defs>
                  <clipPath id="mc"><circle cx="50" cy="50" r="48" /></clipPath>
                </defs>
                <g clipPath="url(#mc)">
                {(() => {
                  const S = 0.96;
                  const hovLevel = hovered ? LEVEL_MAP[hovered] : null;
                  const hovR1 = hovLevel ? hovLevel.r1 : 0;
                  const activeKeys = Object.keys(colorChats);
                  const maxActiveR1 = activeKeys.length > 0 ? Math.max(...activeKeys.map(k => LEVEL_MAP[k]?.r1 || 0)) : 0;
                  const showHov = hovR1 > 0;
                  const showPers = maxActiveR1 > 0 && !showHov;
                  const displayR1 = showHov ? hovR1 : showPers ? maxActiveR1 : 0;
                  const displayClr = hovLevel ? hovLevel.clr : (activeKeys.length > 0 ? LEVEL_MAP[activeKeys[activeKeys.length - 1]]?.clr : "#fff");
                  if (displayR1 <= 0) return null;
                  const r = displayR1 * 50 * S;
                  return (
                    <>
                      {showHov && <>
                        <circle cx="50" cy="50" r={r} fill={displayClr} fillOpacity="0.18" style={{ mixBlendMode: "screen", pointerEvents: "none" }} />
                        <circle cx="50" cy="50" r={r} fill="white" fillOpacity="0.06" style={{ pointerEvents: "none" }} />
                        <circle cx="50" cy="50" r={r} fill="none" stroke={displayClr} strokeOpacity="0.8" strokeWidth="0.5" style={{ pointerEvents: "none" }} />
                      </>}
                      {showPers && <>
                        <circle cx="50" cy="50" r={r} fill={displayClr} fillOpacity="0.08" style={{ mixBlendMode: "screen", pointerEvents: "none" }} />
                      </>}
                    </>
                  );
                })()}
                </g>
              </svg>
              {hoveredLevel && (
                <div className="mandala-hover" style={{ background: hoveredLevel.bg, color: hoveredLevel.clr, border: "1px solid " + hoveredLevel.clr + "40" }}>
                  <div style={{ width: 36, height: 36, borderRadius: 8, background: hoveredLevel.clr + "20", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                    <Ico k={hovered} size={30} />
                  </div>
                  {hoveredLevel.name} {"\u2014"} {hoveredLevel.sub}
                </div>
              )}
            </div>
            )}

            <div className="toggle-wrap">
              <span style={{ opacity: integrated ? .4 : 1 }}>Jednotlivá úroveň</span>
              <div className={"toggle" + (integrated ? " on" : "")} onClick={() => setIntegrated(!integrated)}>
                <div className="toggle-dot" />
              </div>
              <span style={{ opacity: integrated ? 1 : .4 }}>Integrovaný pohľad</span>
            </div>
            <div className="hint">
              {integrated
                ? "Kliknutím otvoríte túto + všetky vnútorné úrovne"
                : viewMode === "icons"
                  ? "Kliknutím na ikonu otvoríte perspektívu danej úrovne"
                  : "Kliknutím na vrstvu mandaly otvoríte perspektívu danej úrovne"}
            </div>

            {openChatKeys.length > 0 && (
              <div style={{ marginTop: 28 }}>
                {openChatKeys.map(key => {
                  const l = LEVEL_MAP[key]; const chat = colorChats[key];
                  const isLoading = colorLoading[key]; const isSel = !!selected[key];
                  return (
                    <div key={key} style={{ display: "flex", marginBottom: 12 }}>
                      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", width: 24, flexShrink: 0, paddingLeft: 6 }}>
                        <div style={{ width: 8, height: 8, borderRadius: "50%", background: l.clr, opacity: .7, flexShrink: 0 }} />
                        <div style={{ width: 2, flexGrow: 1, background: "linear-gradient(to bottom, " + l.clr + "70, " + l.clr + "15)", borderRadius: 1, minHeight: 16 }} />
                      </div>
                      <div className="cp" style={{ background: l.bg, border: "1px solid " + l.clr + (isSel ? "50" : "20"), borderLeft: "3px solid " + l.clr + "50", flexGrow: 1 }}>
                        <div className="ch">
                          <input type="checkbox" className="chk" checked={isSel} onChange={() => toggleSelect(key)} title="Vybrať pre integráciu" style={{ accentColor: l.clr }} />
                          <Ico k={key} size={22} />
                          <span style={{ fontFamily: "'DM Sans',sans-serif", fontSize: 12, fontWeight: 600, letterSpacing: 2, textTransform: "uppercase", color: l.clr }}>{l.name}</span>
                          <button className="cx" onClick={() => closeCC(key)}>{"✕"}</button>
                        </div>
                        <div className="cm">
                          <div style={{ float: "right", width: 70, height: 70, borderRadius: 12, background: l.clr + "15", display: "flex", alignItems: "center", justifyContent: "center", marginLeft: 12, marginBottom: 8 }}>
                            <Ico k={key} size={58} />
                          </div>
                          {chat.messages.map((m, i) => 
                            m.role === "error" ? (
                              <div key={i} style={{ padding: "10px 14px", background: "rgba(248,113,113,.06)", border: "1px solid rgba(248,113,113,.15)", borderRadius: 8, marginBottom: 12 }}>
                                <div style={{ fontFamily: "'DM Sans',sans-serif", fontSize: 13, color: "#F87171", marginBottom: 8 }}>{m.content}</div>
                                <button onClick={() => retryChat(key)} style={{ padding: "5px 14px", background: "rgba(248,113,113,.1)", border: "1px solid rgba(248,113,113,.2)", borderRadius: 6, color: "#F87171", fontFamily: "'DM Sans',sans-serif", fontSize: 12, cursor: "pointer" }}>Skúsiť znova</button>
                              </div>
                            ) : m.role === "user" ? (
                              <div key={i} className="mg mu">{m.content}</div>
                            ) : (
                              <div key={i} className="mg ma">{m.content}</div>
                            )
                          )}
                          {!chat.elaborated && !isLoading && chat.messages.length > 0 && chat.messages[0].role === "assistant" && (
                            <button onClick={() => elaborateChat(key)} style={{ display: "inline-flex", alignItems: "center", gap: 6, padding: "5px 14px", background: l.clr + "0a", border: "1px solid " + l.clr + "25", borderRadius: 7, color: l.clr + "90", fontFamily: "'DM Sans',sans-serif", fontSize: 11, cursor: "pointer", transition: "all .2s", letterSpacing: ".5px", marginBottom: 8 }}>Rozvinúť perspektívu</button>
                          )}
                          {isLoading && <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0" }}><div className="sps" style={{ borderTopColor: l.clr, borderRightColor: l.clr + "60" }} /><span className="lt">Premýšľam...</span></div>}
                        </div>
                        <div className="cr">
                          <input className="ci" value={chat.input} onChange={e => setCCInput(key, e.target.value)} onKeyDown={e => { if (e.key === "Enter") { e.preventDefault(); sendCC(key); }}} placeholder={"Opýtaj sa z pohľadu " + l.name.toLowerCase() + "..."} disabled={isLoading} style={{ borderColor: l.clr + "20" }} />
                          <button className="sb" onClick={() => sendCC(key)} disabled={isLoading || !chat.input.trim()} style={{ background: l.clr + "18", color: l.clr, border: "1px solid " + l.clr + "30" }}>Odoslať</button>
                        </div>
                      </div>
                    </div>
                  );
                })}
                {selectedCount > 0 && (
                  <button className="ib" onClick={integrateSelected}>
                    {"Integrovať " + selectedCount + (selectedCount === 1 ? " perspektívu" : selectedCount < 5 ? " perspektívy" : " perspektív") + " do žltej"}
                  </button>
                )}
              </div>
            )}

            <div className="ms">
              <div className="ml"><Ico k="yellow" size={20} /> Integratívny dialóg <span className="bg2">Žltá</span></div>
              <div className="msl">Pokračuj v skúmaní témy z integratívnej, systémovej perspektívy</div>
              {integratedContext && <div style={{ fontFamily: "'DM Sans',sans-serif", fontSize: 11, color: "rgba(250,204,21,.5)", marginTop: -8, marginBottom: 12, fontStyle: "italic" }}>Integrované perspektívy sú zahrnuté v kontexte</div>}
              {reflection && (
                <div style={{ padding: "12px 16px", marginBottom: 14, background: "rgba(250,204,21,.04)", border: "1px solid rgba(250,204,21,.1)", borderRadius: 10, fontFamily: "'DM Sans',sans-serif", fontSize: 12, fontWeight: 300, lineHeight: 1.7, color: "rgba(250,204,21,.55)", fontStyle: "italic" }}>
                  {reflection}
                </div>
              )}
              {mainChat.length > 0 && <div style={{ marginBottom: 14 }}>
                {mainChat.map((m, i) => <div key={i} className={"mg " + (m.role === "user" ? "mu" : "ma")} style={m.role === "user" ? { borderLeftColor: "rgba(250,204,21,.25)" } : {}}>{m.content}</div>)}
                {mainLoading && <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 0" }}><div className="sps" style={{ borderTopColor: "#FACC15", borderRightColor: "rgba(250,204,21,.3)" }} /><span className="lt">Integrujem perspektívy...</span></div>}
                <div ref={mainEndRef} />
              </div>}
              <div style={{ display: "flex", gap: 8, alignItems: "flex-end" }}>
                <input className="ci" value={mainInput} onChange={e => setMainInput(e.target.value)} onKeyDown={e => { if (e.key === "Enter") { e.preventDefault(); sendMain(); }}} placeholder="Opýtaj sa, rozvíjaj tému integratívne..." disabled={mainLoading} style={{ borderColor: "rgba(250,204,21,.15)" }} />
                <button className="sb" onClick={sendMain} disabled={mainLoading || !mainInput.trim()} style={{ background: "rgba(250,204,21,.1)", color: "#FACC15", border: "1px solid rgba(250,204,21,.2)" }}>Odoslať</button>
              </div>
            </div>
            <div className="ft">Každá perspektíva je autentická {"·"} Žiadna nie je lepšia ani horšia</div>
            <div style={{ textAlign: "center", marginTop: 20 }}>
              <button className="btn" onClick={() => { setTopicSet(""); setTopic(""); }} style={{ fontSize: 11, padding: "8px 24px" }}>Nová téma</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
